#import "NSFileManager+Extension.h"

@implementation NSFileManager (Extension)

+ (NSString *)sandBoxFilePathWithDir:(NSSearchPathDirectory)dir fileName:(NSString *)fileName {
    NSString *dirPath = NSSearchPathForDirectoriesInDomains(dir, NSUserDomainMask, YES)[0];
    return [dirPath stringByAppendingPathComponent:fileName];
}

+ (NSString *)cacheFilePathWithName:(NSString *)fileName {
    return [self sandBoxFilePathWithDir:NSCachesDirectory fileName:fileName];
}

+ (NSString *)documentFilePathWithName:(NSString *)fileName {
    return [self sandBoxFilePathWithDir:NSDocumentDirectory fileName:fileName];
}

+ (id)jsonWithFile:(NSString *)filePath {
    NSFileManager *manager = [NSFileManager defaultManager];
    if (![manager fileExistsAtPath:filePath]) {
        return nil;
    }
    NSData *data = [NSData dataWithContentsOfFile:filePath];
    if (data == nil) {
        return nil;
    }
    return [NSJSONSerialization JSONObjectWithData:data options:NSJSONReadingFragmentsAllowed error:nil];
}

+ (void)saveJson:(id)json toFile:(NSString *)filePath {
    NSData *data = [NSJSONSerialization dataWithJSONObject:json options:NSJSONWritingPrettyPrinted error:nil];
    [data writeToFile:filePath atomically:YES];
}

@end

