#import "NSArray+Extension.h"
#import "PrefixHeader.h"

@implementation NSArray (Extension)

// json数组转模型数组（指定元素的类型）
+ (NSMutableArray *)arrayWithJsonFile:(NSString *)filePath elementClass:(Class)cls {
    NSArray *arrayJson = [NSFileManager jsonWithFile:filePath];
    // jsons字典数组转模型数组后返回
    NSMutableArray *arrayModel = [NSMutableArray arrayWithCapacity:arrayJson.count];

    for (id json in arrayJson) {
        id model = [cls new];
        [model modelSetWithJSON:json];
        [arrayModel addObject:model];
    }

    return arrayModel;
}

@end

