#import "ShowHeaderView.h"
#import "PrefixHeader.h"

@interface ShowHeaderView ()

@end

@implementation ShowHeaderView

- (instancetype)init {
    self = [super init];
    if (self) {
        [self setUpUI];
        [self setUpEvents];
    }
    return self;
}

- (void)setUpEvents {
    [self.returnButton addTarget:self action:@selector(returncliked:) forControlEvents:UIControlEventTouchUpInside];
//    [self.deleteButton addTarget:self action:@selector(returnRightcliked:) forControlEvents:UIControlEventTouchUpInside];
    [self.editButton addTarget:self action:@selector(editTalkcliked:) forControlEvents:UIControlEventTouchUpInside];
}

#pragma mark - ui事件

- (void)returncliked:(UIButton *)sender {
    [sender showClickedAnimationWithLevel:2];
    [self.viewController dismissViewControllerAnimated:YES completion:nil];
}

- (void)returnRightcliked:(UIButton *)sender {
    [sender showClickedAnimationWithLevel:2];
    [self.viewController dismissViewControllerAnimated:YES completion:nil];
}

- (void)editTalkcliked:(UIButton *)sender {
    [sender showClickedAnimationWithLevel:2];
    [[NSNotificationCenter defaultCenter] postNotificationName:@"编辑对话信息" object:nil];
}

-(void)showAppearAnimation {
    [_titleLabel showClickedAnimationWithLevel:20];

    [UIView animateWithDuration:0.4 animations:^{
        self.titleLabel.alpha = 1.0;
    }];

    dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.1 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
        [UIView animateWithDuration:0.5 animations:^{
            self.returnButton.alpha = 1.0;
            self.deleteButton.alpha = 1.0;
            self.editButton.alpha = 1.0;
        }];
    });
}

#pragma mark - setUp

- (void)setUpUI {
    self.backgroundColor = WHITE_COLOR;
    //UIImage *image = [UIImage imageNamed:@"A_"];
    //self.layer.contents = (id)image.CGImage;

    [self addSubview:self.returnButton];
    [self addSubview:self.deleteButton];
    [self addSubview:self.titleLabel];
    [self addSubview:self.editButton];

    [_returnButton mas_makeConstraints:^(MASConstraintMaker *make) {
        make.bottom.equalTo(self).offset(ZOOM(-10));
        make.left.equalTo(self).offset(ZOOM(20));
    }];
    [_deleteButton mas_makeConstraints:^(MASConstraintMaker *make) {
        make.bottom.equalTo(self).offset(ZOOM(-10));
        make.right.equalTo(self.editButton.mas_left).offset(ZOOM(-16));
    }];

    [_titleLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.centerY.equalTo(_returnButton);
        make.centerX.equalTo(self);
//        make.left.equalTo(_returnButton.mas_right).offset(ZOOMW(8));
    }];

    [_editButton mas_makeConstraints:^(MASConstraintMaker *make) {
        make.bottom.equalTo(self).offset(ZOOM(-10));
        make.right.equalTo(self).offset(ZOOM(-20));
    }];

    // 为了后面显示出来的动画，现设为隐藏
    _titleLabel.alpha = 0;
    _returnButton.alpha = 0;
    _deleteButton.alpha = 0;
    _editButton.alpha = 0;
}

#pragma mark - 懒加载

- (UIButton *)returnButton {
    if (_returnButton == nil) {
        // 左上角的叉按钮
        UIButton *returnButton = [UIButton buttonWithType:UIButtonTypeCustom];
        [returnButton setImage:[UIImage imageNamed:@"A_return"] forState:UIControlStateNormal];
        // 扩大触摸范围
        returnButton.hitTestEdgeInsets = UIEdgeInsetsMake(-20, -20, -20, -20);

        _returnButton = returnButton;
    }
    return _returnButton;
}

- (UIButton *)deleteButton {
    if (_deleteButton == nil) {
        // 左上角的叉按钮
        UIButton *returnRightButton = [UIButton buttonWithType:UIButtonTypeCustom];
        [returnRightButton setImage:[UIImage imageNamed:@"A_delete"] forState:UIControlStateNormal];
        // 扩大触摸范围
        returnRightButton.hitTestEdgeInsets = UIEdgeInsetsMake(-20, -20, -20, -20);

        _deleteButton = returnRightButton;
        _deleteButton.hidden = YES;
    }
    return _deleteButton;
}


- (UILabel *)titleLabel {
    if(_titleLabel == nil) {
        _titleLabel = [UILabel labelWithText:@"" fontSize:20 bold:YES textColor:RGB(51, 51, 51)];
    }
    return _titleLabel;
}

- (UIButton *)editButton {
    if (_editButton == nil) {
        // 右上角的三个点按钮
        UIButton *editButton = [UIButton buttonWithType:UIButtonTypeCustom];
//        [editButton setImage:[UIImage imageNamed:@"A_TalkPage_edit_icon"] forState:UIControlStateNormal];
        // 扩大触摸范围
        editButton.hitTestEdgeInsets = UIEdgeInsetsMake(-20, -20, -20, -20);

        _editButton = editButton;
    }
    return _editButton;
}


@end

