+    if (storedType.length == 0) {
+        return [self displayTypeMap][@"Social"];
+    }
+    for (NSString *key in [self displayTypeMap]) {
+        if ([storedType caseInsensitiveCompare:key] == NSOrderedSame) {
+            return [self displayTypeMap][key];
+        }
+    }
+    if ([storedType caseInsensitiveCompare:@"Email"] == NSOrderedSame) {
+        return [self displayTypeMap][@"Mail"];
+    }
+    if ([storedType caseInsensitiveCompare:@"Web"] == NSOrderedSame) {
+        return [self displayTypeMap][@"Website"];
+    }
+    return storedType;
+}
