+- (NSString *)storedTypeForDisplayType:(NSString *)displayType {
+    NSString *trimmed = [displayType stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
+    if (trimmed.length == 0) {
+        return @"";
+    }
+    for (NSString *key in [self displayTypeMap]) {
+        if ([trimmed isEqualToString:[self displayTypeMap][key]]) {
+            return key;
+        }
+    }
+    return trimmed;
 }

