- (UILabel *)createTitleLabelWithText:(NSString *)text {
    UILabel *label = [[UILabel alloc] init];
    label.text = text;
    label.font = KEEPASS_FONT_BOLD(16);
    label.textColor = RGB(51, 51, 51);
    label.numberOfLines = 1;
    return label;
}

- (UILabel *)createSubtitleLabelWithText:(NSString *)text {
    UILabel *label = [[UILabel alloc] init];
    label.text = text;
    label.font = KEEPASS_FONT_Regular(12);
    label.textColor = RGB(142, 142, 147);
    label.numberOfLines = 1;
    return label;
}

- (UIButton *)createImageButtonWithImage:(NSString *)imageName {
    UIButton *button = [UIButton buttonWithType:UIButtonTypeCustom];
    [button setBackgroundImage:[UIImage imageNamed:imageName] forState:UIControlStateNormal];
    button.clipsToBounds = YES;
    button.layer.cornerRadius = ZOOMW(12);
    button.imageView.contentMode = UIViewContentModeScaleAspectFill;
    return button;
}

- (UIView *)createPlayBackground {
    UIView *bg = [[UIView alloc] init];
    bg.layer.borderColor = WHITE_COLOR.CGColor;
    bg.layer.borderWidth = 2;
    bg.layer.cornerRadius = ZOOMW(8);
    bg.backgroundColor = RGBA(255, 255, 255, 0.12);
    bg.userInteractionEnabled = NO;
    return bg;
}

- (UIImageView *)createPlayIcon {
    UIImageView *iv = [[UIImageView alloc] init];
    iv.contentMode = UIViewContentModeScaleAspectFit;
    iv.tintColor = WHITE_COLOR;
    return iv;
}

- (void)updatePlayIcon:(UIImageView *)imageView isPlaying:(BOOL)isPlaying {
    NSString *imageName = isPlaying ? @"pause.fill" : @"play.fill";
    UIImage *image = nil;
    if (@available(iOS 13.0, *)) {
        UIImageSymbolConfiguration *config = [UIImageSymbolConfiguration configurationWithPointSize:14 weight:UIImageSymbolWeightSemibold];
        image = [UIImage systemImageNamed:imageName withConfiguration:config];
        imageView.image = [image imageWithRenderingMode:UIImageRenderingModeAlwaysTemplate];
        return;
    }

    NSString *fallbackImageName = isPlaying ? @"A_Selectedpause" : @"A_Selectedplay";
    imageView.image = [UIImage imageNamed:fallbackImageName];
}

