@interface PlayView ()

@property(strong, nonatomic) ModeView *modeview;
@property (nonatomic, strong) UILabel *currentModeNameLabel;

@property (nonatomic, strong) AVPlayer *player;
@property (nonatomic, strong) id timeObserverToken;
@property (nonatomic, assign) NSInteger currentModeIndex;
@end

static NSInteger const kPlayModeCount = 3;

@implementation PlayView

- (NSArray<NSString *> *)modeDisplayNames {
    return @[@"小提琴", @"钢琴", @"吉他"];
}

- (void)dealloc {
    [self tearDownPlayerObserver];
    [[NSNotificationCenter defaultCenter] removeObserver:self];
}

- (instancetype)init {
    self = [super init];
    if (self) {
        _currentModeIndex = 0;
        [self setUpUI];
        [self setUpEvents];
        [self.modeview updatePlaybackState:NO currentIndex:_currentModeIndex];
    }
    return self;
}

#pragma mark - ui事件

- (void)handleModeButtonTapped:(UIButton *)sender {
    NSInteger tappedIndex = [self indexForModeButton:sender];
    if (tappedIndex == NSNotFound) {
        return;
    }

    if (tappedIndex != self.currentModeIndex) {
        self.currentModeIndex = tappedIndex;
        [self.modeview selectModeAtIndex:tappedIndex];
        [self playCurrentMode];
        return;
    }

    [self togglePlayPause];
}

- (void)togglePlayPause {
    if (self.player == nil || self.player.currentItem == nil) {
        [self playCurrentMode];
        return;
    }

    if (self.player.rate > 0.0) {
        [self.player pause];
    } else {
        [self.player play];
    }
    [self syncPlaybackState];
}

#pragma mark - setUpUI
- (void)setUpUI {
    self.backgroundColor = WHITE_COLOR;

    [self addAllSubviews];
    [self addAllConstraints];
    [self updateCurrentModeName];
}

- (void)addAllSubviews {
    [self addSubview:self.modeview];
    [self addSubview:self.currentModeNameLabel];
}

- (void)addAllConstraints {
    [_modeview mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self).offset(ZOOMW(8));
        make.left.right.equalTo(self);
        make.bottom.equalTo(self.currentModeNameLabel.mas_top).offset(-ZOOMW(22));
    }];

    [self.currentModeNameLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.centerX.equalTo(self);
        make.bottom.equalTo(self.mas_safeAreaLayoutGuideBottom).offset(-ZOOMW(38));
    }];
}

#pragma mark - set up events
- (void)setUpEvents {
    [_modeview.xueshanbotton addTarget:self action:@selector(handleModeButtonTapped:) forControlEvents:UIControlEventTouchUpInside];
    [_modeview.jingmibotton addTarget:self action:@selector(handleModeButtonTapped:) forControlEvents:UIControlEventTouchUpInside];
    [_modeview.caoyuanbotton addTarget:self action:@selector(handleModeButtonTapped:) forControlEvents:UIControlEventTouchUpInside];
}

- (NSInteger)indexForModeButton:(UIButton *)button {
    if (button == self.modeview.xueshanbotton) {
        return 0;
    }
    if (button == self.modeview.jingmibotton) {
        return 1;
    }
    if (button == self.modeview.caoyuanbotton) {
        return 2;
    }
    return NSNotFound;
}

- (void)prepareAudioSessionIfNeeded {
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        AVAudioSession *audioSession = [AVAudioSession sharedInstance];
        [audioSession setCategory:AVAudioSessionCategoryPlayback withOptions:AVAudioSessionCategoryOptionMixWithOthers error:nil];
        [audioSession setActive:YES error:nil];
    });
}

- (void)playCurrentMode {
    NSString *fileName = [self.modeview modeFileAtIndex:self.currentModeIndex];
    NSURL *url = [[NSBundle mainBundle] URLForResource:fileName withExtension:nil];
    if (url == nil) {
        return;
    }

    [self prepareAudioSessionIfNeeded];
    [self replacePlayerItemWithURL:url];
    [self.player play];
    [self syncPlaybackState];
}

- (void)replacePlayerItemWithURL:(NSURL *)url {
    AVPlayerItem *item = [AVPlayerItem playerItemWithURL:url];
    if (self.player == nil) {
        self.player = [AVPlayer playerWithPlayerItem:item];
        [self installPlayerObserverIfNeeded];
    } else {
        [self.player replaceCurrentItemWithPlayerItem:item];
    }

    [[NSNotificationCenter defaultCenter] removeObserver:self
                                                    name:AVPlayerItemDidPlayToEndTimeNotification
                                                  object:nil];
    [[NSNotificationCenter defaultCenter] addObserver:self
                                             selector:@selector(runLoopTheMovie:)
                                                 name:AVPlayerItemDidPlayToEndTimeNotification
                                               object:item];
}

- (void)playNextMode {
    self.currentModeIndex = (self.currentModeIndex + 1) % kPlayModeCount;
    [self.modeview selectModeAtIndex:self.currentModeIndex];
    [self updateCurrentModeName];
    [self playCurrentMode];
}

- (void)runLoopTheMovie:(NSNotification *)notification {
    __weak typeof(self) weakSelf = self;
    [self.player seekToTime:kCMTimeZero completionHandler:^(BOOL finished) {
        if (!finished) {
            return;
        }
        [weakSelf.player play];
        [weakSelf syncPlaybackState];
    }];
}

- (void)installPlayerObserverIfNeeded {
    if (self.player == nil || self.timeObserverToken != nil) {
        return;
    }

    __weak typeof(self) weakSelf = self;
    self.timeObserverToken = [self.player addPeriodicTimeObserverForInterval:CMTimeMake(1, 5)
                                                                       queue:dispatch_get_main_queue()
                                                                  usingBlock:^(CMTime time) {
        [weakSelf syncPlaybackState];
    }];
}

- (void)tearDownPlayerObserver {
    if (self.player != nil && self.timeObserverToken != nil) {
        [self.player removeTimeObserver:self.timeObserverToken];
        self.timeObserverToken = nil;
    }
}

- (void)syncPlaybackState {
    BOOL isPlaying = self.player != nil && self.player.rate > 0.0 && self.player.error == nil;
    [self.modeview updatePlaybackState:isPlaying currentIndex:self.currentModeIndex];
    [self updateCurrentModeName];
}

- (void)updateCurrentModeName {
    NSInteger safeIndex = MAX(0, MIN(self.currentModeIndex, self.modeDisplayNames.count - 1));
    self.currentModeNameLabel.text = self.modeDisplayNames[safeIndex];
}

#pragma mark - 初始化私有成员
- (ModeView *)modeview {
    if (_modeview == nil) {
        _modeview = [[ModeView alloc] init];
    }
    return _modeview;
}

- (UILabel *)currentModeNameLabel {
    if (_currentModeNameLabel == nil) {
        _currentModeNameLabel = [[UILabel alloc] init];
        _currentModeNameLabel.textAlignment = NSTextAlignmentCenter;
        _currentModeNameLabel.font = KEEPASS_FONT_BOLD(22);
        _currentModeNameLabel.textColor = RGBA(82, 82, 82, 1);
    }
    return _currentModeNameLabel;
}

@end

