- (void)read {
    if (self.passwordTextField.text.length == 0) return;

    // 停止上一次的播放（立即停止，不保留队列）
    if (self.speechSynthesizer.isSpeaking) {
        [self.speechSynthesizer stopSpeakingAtBoundary:AVSpeechBoundaryImmediate];
    }

    // 确保音频会话可用
    AVAudioSession *audioSession = [AVAudioSession sharedInstance];
    [audioSession setCategory:AVAudioSessionCategoryPlayback error:nil];
    [audioSession setActive:YES error:nil];

    NSString *text = self.passwordTextField.text;

    NSMutableString *letterByLetterText = [NSMutableString string];
    for (NSUInteger i = 0; i < text.length; i++) {
        unichar c = [text characterAtIndex:i];
        [letterByLetterText appendFormat:@"%C ", c];
    }

    AVSpeechUtterance *utterance = [[AVSpeechUtterance alloc] initWithString:letterByLetterText];
    utterance.voice = [AVSpeechSynthesisVoice voiceWithIdentifier:@"com.apple.voice.compact.zh-CN.Tingting"];

    [self.speechSynthesizer speakUtterance:utterance];
}



