- (NSArray<NSString *> *)candidateTypeKeysForCurrentType {
    NSString *typeKey = self.text ?: @"";
    if ([typeKey caseInsensitiveCompare:@"Mail"] == NSOrderedSame || [typeKey caseInsensitiveCompare:@"Email"] == NSOrderedSame) {
        return @[@"Mail", @"Email"];
