   444	- (NSInteger)getStringWidthToCellHeight:(NSString *)string {
   445	    // 将文本分割为行
   446	    NSArray *lines = [string componentsSeparatedByString:@"\n"];
   447	    
   448	    // 计算空行数
   449	    NSPredicate *isEmptyLinePredicate = [NSPredicate predicateWithBlock:^BOOL(id _Nullable evaluatedObject, NSDictionary * _Nullable bindings) {
   450	        return ([evaluatedObject isKindOfClass:[NSString class]] && [(NSString *)evaluatedObject length] == 0);
   451	    }];
   452	    NSArray *emptyLines = [lines filteredArrayUsingPredicate:isEmptyLinePredicate];
   453	    NSInteger emptyLineCount = (NSInteger)emptyLines.count;
   454	    
   455	    // 使用系统字体进行计算
   456	    UIFont *font = [UIFont systemFontOfSize:16.0];
   457	    
   458	    // 计算实际文本的行数
   459	    CGFloat totalTextHeight = 0.0;
   460	    for (NSString *line in lines) {
   461	        if (![emptyLines containsObject:line]) { // 只处理非空行
   462	            // 使用boundingRect来计算文本占用的实际高度
   463	            CGSize maxSize = CGSizeMake(ZOOM(260), CGFLOAT_MAX);  // 最大宽度
   464	            
   465	            CGRect textRect = [line boundingRectWithSize:maxSize
   466	                                                 options:NSStringDrawingUsesLineFragmentOrigin
   467	                                              attributes:@{NSFontAttributeName: font}
   468	                                                 context:nil];
   469	            // 每一行的高度由文本占用的高度决定
   470	            totalTextHeight += textRect.size.height;
   471	        }
   472	    }
   473	    
   474	    // 计算 cell 的总高度
   475	    CGFloat cellHeight = totalTextHeight              // 计算所有文本行的总高度
